sql:
SELECT company_name, taxi_type, company_fleet_size 
FROM taxi_companies 
WHERE taxi_type = 'yellow' AND company_fleet_size > 200;

SELECT company_name, taxi_type
FROM taxi_companies
WHERE company_fleet_size > 200;

SELECT driver_name
FROM drivers
WHERE driver_rating = (
  SELECT MAX(driver_rating)
  FROM drivers
);

SELECT MAX(years_of_experience)
FROM drivers
WHERE company_id = 1;

external_knowledge:
- "most distinguished captains" refers to drivers with a driver rating of 4.5 or higher;
- "voyages" are represented by trips in the database;
- "embarked on voyages" means participating in trips through taxi services.

sql:
SELECT COUNT(*) 
FROM trip_locations 
WHERE pickup_zip_code_round3 = '10019' OR dropoff_zip_code_round3 = '10019';

SELECT pickup_latitude_round3, pickup_longitude_round3
FROM trip_locations
WHERE trip_id = 0;

SELECT AVG(driver_rating) 
FROM drivers 
WHERE years_of_experience > 4 AND driver_status = 'active';
